import sys
import copy

def read_grid():
    grid = []
    for _ in range(3):
        grid.append(list(map(int, sys.stdin.readline().split())))
    return grid

def is_win(board, player):
    # Check rows
    for i in range(3):
        if all(board[i][j] == player for j in range(3)):
            return True
    # Check columns
    for j in range(3):
        if all(board[i][j] == player for i in range(3)):
            return True
    # Check diagonals
    if all(board[i][i] == player for i in range(3)):
        return True
    if all(board[i][2-i] == player for i in range(3)):
        return True
    return False

def game_over(board):
    # Check if any player has won
    if is_win(board, 'T') or is_win(board, 'A'):
        return True
    # Check if all cells are filled
    for row in board:
        if 0 in row:
            return False
    return True

