def minimax(board, scores, turn, depth):
    if game_over(board):
        if is_win(board, 'T'):
            return (1, None)
        elif is_win(board, 'A'):
            return (-1, None)
        else:
            t_score = get_score(board, 'T')
            a_score = get_score(board, 'A')
            if t_score > a_score:
                return (1, None)
            elif a_score > t_score:
                return (-1, None)
